import { describe, expect, it } from "vitest";
import { parseUpdateMode } from "./update.js";
describe("parseUpdateMode", () => {
    it('defaults to "all" for undefined', () => {
        expect(parseUpdateMode(undefined)).toBe("all");
    });
    it('accepts "all"', () => {
        expect(parseUpdateMode("all")).toBe("all");
    });
    it('accepts "plugin"', () => {
        expect(parseUpdateMode("plugin")).toBe("plugin");
    });
    it('accepts "sdk"', () => {
        expect(parseUpdateMode("sdk")).toBe("sdk");
    });
    it("throws on unknown modes", () => {
        expect(() => parseUpdateMode("everything")).toThrow(/Unknown update mode/);
    });
});
